import { test as base } from "@playwright/test";
import { MockClient } from "request-mocking-protocol";
import { setupPlaywrightInterceptor } from "request-mocking-protocol/playwright";

export const test = base.extend<{ mockServerRequest: MockClient }>({
  mockServerRequest: async ({ context, page, baseURL }, use) => {
    const localOrigin = baseURL ? new URL(baseURL).origin : undefined;
    const isSpecialScheme = (url: string) =>
      url.startsWith("about:") ||
      url.startsWith("blob:") ||
      url.startsWith("data:");

    await page.route(
      (url) => {
        const href = url.toString();
        if (!localOrigin || isSpecialScheme(href)) {
          return false;
        }
        try {
          return new URL(href).origin !== localOrigin;
        } catch {
          return false;
        }
      },
      async (route) => {
        await route.abort();
        throw new Error(
          `[Playwright] Blocked external browser request: ${route.request().method()} ${route.request().url()}\n All requests to external APIs must flow through server functions`,
        );
      },
    );

    const mockClient = new MockClient();
    mockClient.onChange = async (headers) =>
      context.setExtraHTTPHeaders(headers);
    await setupPlaywrightInterceptor(page, mockClient);
    await use(mockClient);
    await page.unroute("**");
  },
});

export { expect } from "@playwright/test";

